  voip:          { count: 1,  naming: () => 'eth0' },
  iot:           { count: 1,  naming: () => 'eth0' },
  'load-balancer': { count: 4, naming: i => `eth${i}` },
  ids:           { count: 2,  naming: i => `eth${i}` },
  wlc:           { count: 2,  naming: i => `eth${i}` },
  'public-web':  { count: 1,  naming: () => 'eth0' },
