  'public-cloud':{ count: 1,  naming: () => 'eth0' },
  // Cloud networking
  'vpc':          { count: 4,  naming: i => `eni${i}` },
  'cloud-subnet': { count: 2,  naming: i => `eni${i}` },
  'igw':          { count: 2,  naming: i => `eni${i}` },
