        <path d="M -28 -4 L 28 -4 M -28 8 L 28 8 M -14 -14 L -14 -4 M 0 -4 L 0 8 M 14 -14 L 14 -4 M -14 8 L -14 18 M 14 8 L 14 18" ${s}/>
