      const srv1  = _tbMkDev({ type: 'server',    x: 300, y: 280, hostname: 'App-Server-01', ip: '10.100.0.10' });
      const srv2  = _tbMkDev({ type: 'server',    x: 300, y: 500, hostname: 'App-Server-02', ip: '10.100.0.11' });
