        hint: 'ARP maps IP → MAC within a broadcast domain. You don\'t need a router for this lab since all devices are on the same subnet.',
        check: (s) => s.devices.filter(d => d.type === 'pc' && d.interfaces.some(i => i.ip)).length >= 3,
