    id: 'attack-defense',
    title: 'Network Attack & Defense Lab',
    objective: '4.2',
    difficulty: 'Intermediate',
    duration: '15 min',
    description: 'Simulate ARP spoofing, VLAN hopping, and rogue DHCP attacks — then enable DAI, DHCP snooping, and port security to defend against them.',
