function aclCloseAddRuleModal() {
  const modal = document.getElementById('acl-rule-modal');
  if (modal) modal.classList.add('is-hidden');
}

function aclSubmitAddRule() {
  const get = id => { const el = document.getElementById(id); return el ? el.value.trim() : ''; };
  const rule = {
    action:  get('acl-rm-action')  || 'permit',
    proto:   get('acl-rm-proto')   || 'any',
    srcAddr: get('acl-rm-srcAddr') || 'any',
    srcPort: get('acl-rm-srcPort') || 'any',
    dstAddr: get('acl-rm-dstAddr') || 'any',
    dstPort: get('acl-rm-dstPort') || 'any'
  };
  // Light validation on IPs (allow 'any' or CIDR / bare IP)
  const ipOk = v => v === 'any' || _aclIpToUint(v.split('/')[0]) !== null;
  if (!ipOk(rule.srcAddr)) { alert('Source address must be an IP, CIDR, or "any".'); return; }
  if (!ipOk(rule.dstAddr)) { alert('Dest address must be an IP, CIDR, or "any".');   return; }
  aclAddRule(rule);
  aclCloseAddRuleModal();
}

// ── AI Coach (Tier C, cached) ──
// Same architectural shape as tbCoachTopology: check cache by scenario+rules
// hash, show loading modal, call Sonnet, render structured response, cache.
function _aclRulesHash() {
  const scenId = aclState.scenarioId || 'free-build';
  const rulesKey = aclState.rules.map(r => [r.action, r.proto, r.srcAddr, r.srcPort, r.dstAddr, r.dstPort].join('|')).join('\n');
  // djb2-style hash, matches style used in tbTopologyHash
  let h = 5381;
  const s = scenId + '::' + rulesKey;
  for (let i = 0; i < s.length; i++) h = (((h << 5) + h) + s.charCodeAt(i)) | 0;
  return (h >>> 0).toString(36);
}

// v4.55.2: Progressive-hint ladder. 3 tiers of authored nudges per
// scenario (general \u2192 specific \u2192 exact). Solution reveal unlocks only
// after tier-3 is used. Client-side, zero API cost.
function aclShowHint() {
  const scen = aclActiveScenario();
  if (!scen || !Array.isArray(scen.hints) || scen.hints.length === 0) return;
  const used = (aclState.hintsUsed[scen.id] || 0);
  const nextTier = Math.min(used + 1, scen.hints.length);
  aclState.hintsUsed[scen.id] = nextTier;
  aclSaveState();
  _aclRenderHintModal(scen, nextTier);
  renderAclPage(); // refresh the Hint button label ("Hint (N left)")
}
function _aclRenderHintModal(scen, tier) {
  const modal = document.getElementById('acl-hint-modal');
  const body = document.getElementById('acl-hint-body');
  if (!modal || !body) return;
  const tierCopy = ['general nudge', 'more specific', 'near-exact'][tier - 1] || 'hint';
  const hintText = scen.hints[tier - 1] || '';
  const esc = typeof escHtml === 'function' ? escHtml : (s => s);
  const tiersHtml = scen.hints.slice(0, tier).map((h, i) => `
    <div class="acl-hint-tier acl-hint-tier-${i === tier - 1 ? 'current' : 'past'}">
      <div class="acl-hint-tier-label">Tier ${i + 1} \u00b7 ${['general nudge', 'more specific', 'near-exact'][i] || 'hint'}</div>
      <div class="acl-hint-tier-text">${esc(scen.hints[i])}</div>
    </div>
  `).join('');
  const hasSolution = Array.isArray(scen.solution) && scen.solution.length > 0;
  const solutionUnlocked = tier >= scen.hints.length;
  const solutionBtn = hasSolution && solutionUnlocked
    ? `<button type="button" class="btn btn-ghost acl-hint-solution-btn" onclick="aclShowSolution()">\ud83d\udd13 Show solution rule list</button>`
    : '';
  body.innerHTML = `
    <div class="acl-hint-tiers">${tiersHtml}</div>
    ${solutionBtn}
    <div class="acl-hint-foot">Tier ${tier} of ${scen.hints.length} \u00b7 ${tier < scen.hints.length ? 'Click Hint again for more.' : 'Final tier reached.'}</div>
  `;
  modal.hidden = false;
}
function dismissHintModal() {
  const modal = document.getElementById('acl-hint-modal');
  if (modal) modal.hidden = true;
}
function aclShowSolution() {
  const scen = aclActiveScenario();
  if (!scen || !Array.isArray(scen.solution)) return;
  aclState.solutionShown[scen.id] = true;
  aclSaveState();
  const body = document.getElementById('acl-hint-body');
  if (!body) return;
  const esc = typeof escHtml === 'function' ? escHtml : (s => s);
  const rulesList = scen.solution.map((r, i) => `
    <div class="acl-sol-rule">
      <span class="acl-sol-num">${i + 1}</span>
      <span class="acl-sol-action acl-sol-action-${r.action}">${r.action}</span>
      <span class="acl-sol-proto">${esc(r.proto || 'any')}</span>
      <span class="acl-sol-addr">${esc(r.srcAddr || 'any')}</span>
      <span class="acl-sol-sep">\u2192</span>
      <span class="acl-sol-addr">${esc(r.dstAddr || 'any')}:${esc(String(r.dstPort || 'any'))}</span>
      ${r.comment ? `<div class="acl-sol-comment">${esc(r.comment)}</div>` : ''}
    </div>
  `).join('');
  body.innerHTML = `
    <div class="acl-hint-eyebrow">\ud83d\udd13 Solution \u00b7 golden rule list</div>
    <div class="acl-sol-rules">${rulesList}</div>
    <p class="acl-hint-foot">This is one canonical solution. Your answer may differ in wording but produce equivalent behaviour.</p>
    <button type="button" class="btn btn-primary acl-sol-apply" onclick="aclApplySolution()">\ud83c\udfaf Apply this solution to my rules</button>
  `;
}
function aclApplySolution() {
  const scen = aclActiveScenario();
  if (!scen || !Array.isArray(scen.solution)) return;
  aclState.rules = scen.solution.map(r => ({ ...r, id: r.id || ('r_sol_' + Math.random().toString(36).slice(2, 8)) }));
  aclSaveState();
  dismissHintModal();
  renderAclPage();
  if (typeof showSuccessToast === 'function') showSuccessToast('Solution applied. Run Test All to verify.');
}

function _aclLoadCoachCache() {
  try { return JSON.parse(localStorage.getItem(STORAGE.ACL_COACH_CACHE) || '{}'); }
  catch (_) { return {}; }
}
function _aclSaveCoachCache(cache) {
  const entries = Object.entries(cache);
  const trimmed = entries.length > 20 ? Object.fromEntries(entries.sort((a, b) => (b[1].t || 0) - (a[1].t || 0)).slice(0, 20)) : cache;
  try { localStorage.setItem(STORAGE.ACL_COACH_CACHE, JSON.stringify(trimmed)); } catch (_) {}
}

async function aclAskCoach() {
  const scen = aclActiveScenario();
  if (scen.id === 'free-build') {
    if (typeof showErrorToast === 'function') showErrorToast('AI Coach is scenario-specific \u2014 pick a scenario first.');
    return;
  }
  if (aclState.rules.length === 0) {
    if (typeof showErrorToast === 'function') showErrorToast('Add some rules before asking the Coach.');
    return;
  }
  const key = (localStorage.getItem(STORAGE.KEY) || '').trim();
  if (!key) {
    if (typeof showErrorToast === 'function') showErrorToast('Add your Anthropic API key in Settings to use the Coach.');
    return;
  }
  const hash = _aclRulesHash();
  const cache = _aclLoadCoachCache();
  if (cache[hash] && cache[hash].payload) {
    _aclShowCoachModal(cache[hash].payload, scen, /*cached=*/true);
    return;
  }
  _aclShowCoachModalLoading(scen);
  // Build a plain-text ACL serialization for the prompt
  const rulesText = aclState.rules.length
    ? aclState.rules.map((r, i) => `${i + 1}. ${r.action} ${r.proto} ${r.srcAddr}:${r.srcPort} \u2192 ${r.dstAddr}:${r.dstPort}`).join('\n')
    : '(empty rule list)';
  const g = _aclGradeScenario(aclState.rules, scen);
  const gradeText = g.details.length
    ? g.details.map(d => `  - ${d.label}: expected ${d.expected}, got ${d.actual}${d.implicit ? ' (implicit deny)' : ` (rule #${d.ruleIdx + 1})`} \u2014 ${d.pass ? 'PASS' : 'FAIL'}`).join('\n')
    : '(no grading data)';
  const prompt = `You are a CompTIA Network+ (N10-009) instructor reviewing a student's Access Control List for the following scenario. Be direct, specific, and tie observations to Security-domain exam concepts. Focus on why their rule list passes/fails the test packets \u2014 especially rule ordering and implicit-deny behaviour.

SCENARIO: ${scen.title}
${scen.description}

REQUIREMENTS:
${scen.requirements.map((r, i) => (i + 1) + '. ' + r).join('\n')}

STUDENT'S RULE LIST:
${rulesText}

GRADER OUTPUT (${g.passed}/${g.total} passing):
${gradeText}

Respond with ONLY a JSON object (no preamble, no markdown fences) with these keys:
{
  "tour": "A 2-3 sentence plain-English walkthrough of what their rule list actually DOES when packets hit it.",
  "strengths": ["2-3 things they got right"],
  "concerns": ["1-3 specific issues with this rule list \u2014 wrong rule order, missing rule, wrong port, etc. Reference rule numbers."],
  "fixes": ["2-3 concrete edits to make. Be specific: 'swap rules 1 and 2', 'add a permit for UDP 53', etc."],
  "concept": "1 N10-009 concept this scenario really teaches \u2014 first-match-wins, implicit deny, specific-before-general, layered defence."
}

Keep total response under 400 words. Respond with ONLY the JSON object.`;
  try {
    const res = await fetch(CLAUDE_API_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': key,
        'anthropic-version': '2023-06-01',
        'anthropic-dangerous-direct-browser-access': 'true'
      },
      body: JSON.stringify({ model: CLAUDE_TEACHER_MODEL, max_tokens: MAX_TOKENS_TEACHER_DEFAULT, messages: [{ role: 'user', content: prompt }] })
    });
    if (!res.ok) {
      const errText = await res.text().catch(() => '');
      _aclShowCoachModalError(`API returned ${res.status}. ${errText.slice(0, 160)}`);
      return;
    }
    const data = await res.json();
    const text = (data.content && data.content[0] && data.content[0].text) || '';
    const cleaned = text.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/, '').trim();
    let payload;
    try { payload = JSON.parse(cleaned); }
    catch (e) {
      const m = cleaned.match(/\{[\s\S]*\}/);
      if (m) { try { payload = JSON.parse(m[0]); } catch (_) {} }
    }
    if (!payload || !payload.tour) {
      _aclShowCoachModalError('Coach returned an unexpected response. Try again.');
      return;
    }
    cache[hash] = { t: Date.now(), payload };
    _aclSaveCoachCache(cache);
    _aclShowCoachModal(payload, scen, /*cached=*/false);
  } catch (e) {
    _aclShowCoachModalError(e && e.message ? e.message : 'Network error.');
  }
}

function _aclShowCoachModalLoading(scen) {
  const modal = document.getElementById('acl-coach-modal');
  const body = document.getElementById('acl-coach-body');
  if (!modal || !body) return;
  modal.classList.remove('is-hidden');
  body.innerHTML = `
    <div class="tb-coach-loading">
      <div class="tb-coach-spinner"></div>
      <div class="tb-coach-loading-text">
        <strong>Coach is analysing your ACL\u2026</strong>
        <div class="tb-coach-loading-sub">Scenario: ${escHtml(scen.title)} &middot; usually 3\u20135 seconds</div>
      </div>
    </div>`;
}

function _aclShowCoachModalError(msg) {
  const body = document.getElementById('acl-coach-body');
  if (!body) return;
  body.innerHTML = `
    <div class="tb-coach-error">
      <div class="tb-coach-error-title">\u26A0 Coach couldn\'t reach the API</div>
      <div class="tb-coach-error-msg">${escHtml(msg)}</div>
      <button type="button" class="btn btn-ghost" onclick="aclAskCoach()" style="margin-top:12px">Retry</button>
    </div>`;
}

function _aclShowCoachModal(payload, scen, cached) {
  const modal = document.getElementById('acl-coach-modal');
  const body = document.getElementById('acl-coach-body');
  if (!modal || !body) return;
  modal.classList.remove('is-hidden');
  const list = arr => Array.isArray(arr) && arr.length
    ? `<ul class="tb-coach-list">${arr.map(x => `<li>${escHtml(String(x))}</li>`).join('')}</ul>`
    : '<div class="tb-coach-empty">(none)</div>';
  body.innerHTML = `
    <div class="tb-coach-content">
      <div class="tb-coach-tour">${escHtml(payload.tour || '')}</div>
      <div class="tb-coach-grid">
        <div class="tb-coach-sec"><h4>\u2714 Strengths</h4>${list(payload.strengths)}</div>
        <div class="tb-coach-sec"><h4>\u26A0 Concerns</h4>${list(payload.concerns)}</div>
        <div class="tb-coach-sec"><h4>\ud83d\udd27 Fixes</h4>${list(payload.fixes)}</div>
      </div>
      <div class="tb-coach-concept"><strong>\ud83c\udf93 Concept:</strong> ${escHtml(payload.concept || '')}</div>
      ${cached ? '<div class="tb-coach-cached">Cached \u2014 same rule list as before.</div>' : ''}
    </div>`;
}

function aclCloseCoachModal() {
  const modal = document.getElementById('acl-coach-modal');
  if (modal) modal.classList.add('is-hidden');
}

// ══════════════════════════════════════════
// v4.53.0 — EDITORIAL REDESIGN
// ══════════════════════════════════════════
// Persistent left sidebar + setup-page focus banner + domain grid.
// User asked for this after reviewing a Claude Design prototype — kept our
// brand palette + Inter font + dark/light modes, but adopted the prototype's
// sidebar IA (Practice / Drills sections) and editorial numbered-section
// pattern for the setup page.

// ── Sidebar structure ──
// Two sections: Practice (core study surfaces) + Drills (muscle-memory reps).
// Each item carries page-id + handler + optional icon. Active state is synced
// from showPage() via updateSidebarActiveState().
const APP_SIDEBAR_PRACTICE = [
  { page: 'setup',             label: 'Home',             icon: '\u2302', handler: () => goSetup() },
  { page: 'progress',          label: 'Progress',         icon: '\u25A4', handler: () => { showPage('progress'); if (typeof renderProgressPage === 'function') renderProgressPage(); } },
  { page: 'analytics',         label: 'Analytics',        icon: '\u25A9', handler: () => { showPage('analytics'); if (typeof renderAnalytics === 'function') renderAnalytics(); } },
  { page: 'topology-builder',  label: 'Network Builder',  icon: '\u25C7', handler: () => { showPage('topology-builder'); if (typeof openTopologyBuilder === 'function') openTopologyBuilder(); } },
  { page: 'acl',               label: 'ACL Builder',      icon: '\u25A3', handler: () => { showPage('acl'); if (typeof openAclBuilder === 'function') openAclBuilder(); } }
];
// v4.54.1: Settings section (own sidebar section so it's visually separate from study tools)
const APP_SIDEBAR_SETTINGS = [
  { page: 'settings',          label: 'Settings',         icon: '\u2699', handler: () => { showPage('settings'); if (typeof renderSettingsPage === 'function') renderSettingsPage(); } }
];
const APP_SIDEBAR_DRILLS = [
  { page: 'subnet',            label: 'Subnet Mastery',   handler: () => { showPage('subnet'); if (typeof startSubnetTrainer === 'function') startSubnetTrainer(); } },
  { page: 'ports',             label: 'Port Drill',       handler: () => { showPage('ports'); if (typeof startPortDrill === 'function') startPortDrill(); } },
  { page: 'acronyms',          label: 'Acronym Blitz',    handler: () => { showPage('acronyms'); if (typeof startAcronymBlitz === 'function') startAcronymBlitz(); } },
  { page: 'osi-sorter',        label: 'OSI Sorter',       handler: () => { showPage('osi-sorter'); if (typeof startOsiSorter === 'function') startOsiSorter(); } },
  { page: 'cables',            label: 'Cable ID',         handler: () => { showPage('cables'); if (typeof startCableId === 'function') startCableId(); } }
];

// Map arbitrary page names to their sidebar highlight target. Quiz/exam/review
// etc. all highlight "Home" because they're part of the setup\u2192study flow.
const SIDEBAR_ACTIVE_MAP = {
  'setup': 'setup', 'quiz': 'setup', 'exam': 'setup',
  'results': 'setup', 'exam-results': 'setup', 'review': 'setup',
  'session-transition': 'setup', 'session-complete': 'setup', 'loading': 'setup',
  'progress': 'progress',
  'analytics': 'analytics',
  'topology-builder': 'topology-builder',
  'guided-lab': 'topology-builder',
  'acl': 'acl',
  'subnet': 'subnet',
  'ports': 'ports',
  'acronyms': 'acronyms',
  'osi-sorter': 'osi-sorter',
  'cables': 'cables',
  'topic-dive': 'progress',
  'drills': 'setup',  // launcher shell; highlight Home until specific drill chosen
  'settings': 'settings'
};

// Stash the click handlers on a global so inline onclick="..." can reach them.
// Not elegant but avoids wiring every button with a JS reference.
window.__aclSidebarHandlers = {};

function renderAppSidebar() {
  const el = document.getElementById('app-sidebar');
  if (!el) return;
  // Register handlers keyed by page id, then generate HTML with onclick refs.
  const reg = window.__aclSidebarHandlers;
  [...APP_SIDEBAR_PRACTICE, ...APP_SIDEBAR_DRILLS, ...APP_SIDEBAR_SETTINGS].forEach(it => {
    reg[it.page] = it.handler;
  });
  // v4.54.9: sidebar nav-count pills retired per user request \u2014 the numbers
  // weren't actionable; the drill entries read cleaner without them.
  const renderItem = it => {
    const hasIcon = it.icon;
    return `<button type="button" class="sb-item" data-sb-page="${it.page}" onclick="__aclSidebarHandlers['${it.page}'] && __aclSidebarHandlers['${it.page}']()">
      ${hasIcon ? `<span class="sb-item-icon" aria-hidden="true">${it.icon}</span>` : '<span class="sb-item-icon">&bull;</span>'}
      <span class="sb-item-label">${escHtml(it.label)}</span>
    </button>`;
  };
  // Streak badge in footer — reuses existing getStreak()
  let streakHtml = '';
  try {
    const s = (typeof getStreak === 'function') ? getStreak() : { current: 0, best: 0 };
    if (s && s.current >= 1) {
      const fire = s.current >= 14 ? '\ud83d\udd25\ud83d\udd25' : '\ud83d\udd25';
      streakHtml = `<button type="button" class="sb-streak sb-streak-active" onclick="goSetup()" title="View full streak history">
        <span class="sb-streak-flame" aria-hidden="true">${fire}</span>
        <span class="sb-streak-text">
          <span class="sb-streak-num">${s.current}</span>
          <span class="sb-streak-label">day streak</span>
        </span>
      </button>`;
    } else {
      streakHtml = `<div class="sb-streak-empty">Take your first quiz to start a streak \ud83d\udd25</div>`;
    }
  } catch (_) { streakHtml = ''; }

  el.innerHTML = `
    <div class="sb-brand">
      <div class="sb-brand-mark" aria-hidden="true">N+</div>
      <div class="sb-brand-text">
        <span class="sb-brand-name">Network+</span>
        <span class="sb-brand-version">v${typeof APP_VERSION !== 'undefined' ? APP_VERSION : '4.53.0'}</span>
      </div>
    </div>
    <div class="sb-section">
      <div class="sb-section-label">Practice</div>
      ${APP_SIDEBAR_PRACTICE.map(renderItem).join('')}
    </div>
    <div class="sb-section">
      <div class="sb-section-label">Drills</div>
      ${APP_SIDEBAR_DRILLS.map(renderItem).join('')}
    </div>
    <div class="sb-section">
      <div class="sb-section-label">Account</div>
      ${APP_SIDEBAR_SETTINGS.map(renderItem).join('')}
    </div>
    <div class="sb-foot">${streakHtml}</div>`;
  // Initial active-state sync
  const active = document.querySelector('.page.active');
  if (active) {
    const pageName = active.id.replace(/^page-/, '');
    updateSidebarActiveState(pageName);
  }
}

function updateSidebarActiveState(pageName) {
  const target = SIDEBAR_ACTIVE_MAP[pageName] || pageName;
  document.querySelectorAll('.sb-item').forEach(btn => {
    btn.classList.toggle('sb-item-active', btn.getAttribute('data-sb-page') === target);
  });
}

function toggleSidebarMobile() {
  document.body.classList.toggle('sidebar-open');
}

// ── Focus banner pullquote (setup page) ──
// Real-data greeting with weakest-topic callout + today's daily-goal stats.
// Falls back to friendly empty state when history is empty (first-run).
function renderSetupFocusBanner() {
  const el = document.getElementById('focus-banner');
  if (!el) return;
  const history = (typeof loadHistory === 'function') ? loadHistory() : [];
  const hour = new Date().getHours();
  const greeting = hour < 5 ? 'Working late' : hour < 12 ? 'Good morning' : hour < 17 ? 'Good afternoon' : hour < 21 ? 'Good evening' : 'Working late';
  const greetingLine = `${greeting}, <em>Simi</em>`;

  let bodyHtml, metaHtml, ctaLabel, ctaAction;
  if (history.length === 0) {
    bodyHtml = `<div class="focus-greeting">${greetingLine}</div>
      <div class="focus-text">Start with a <strong>5-minute warmup</strong>. Pick any preset below \u2014 your readiness appears here after your first quiz.</div>
      <div class="focus-meta">N10-009 \u00b7 90Q exam \u00b7 passing score 720/900</div>`;
    ctaLabel = 'Start warmup';
    ctaAction = "applyPreset('warmup')";
  } else {
    // Pull weakest topic + readiness delta
    let weakLine = '';
    try {
      if (typeof computeWeakSpotScores === 'function') {
        const weak = computeWeakSpotScores();
        if (weak && weak.length > 0) {
          const topWeak = weak.slice(0, 2).map(w => `<strong>${escHtml(w.topic)}</strong>`).join(' and ');
          weakLine = `Your weakest areas right now: ${topWeak}.`;
        }
      }
    } catch (_) {}
    if (!weakLine) weakLine = 'Pick a topic below or dive into your weakest domain.';
    bodyHtml = `<div class="focus-greeting">${greetingLine}</div>
      <div class="focus-text">${weakLine} <em>Fifteen focused minutes</em> now compounds more than an hour tomorrow.</div>
      <div class="focus-meta">TODAY'S STUDY PLAN \u00b7 WEAK-SPOT DRILL \u00b7 ~15 MIN</div>`;
    ctaLabel = 'Begin plan';
    ctaAction = "applyPreset('focused')";
  }

  // v4.54.0: Emit the full-width purple-gradient banner structure.
  // Simpler DOM than v4.53.0 — single line of "study plan" copy, accent-highlighted verb,
  // and a white-pill CTA. Matches the mockup screenshot exactly.
  let planText, planMeta;
  if (history.length === 0) {
    planText = `Start with a <em>5-minute warmup</em> \u2014 your readiness appears here after your first quiz.`;
    planMeta = 'TODAY\u2019S STUDY PLAN \u00B7 WARMUP \u00B7 ~5 MIN';
  } else {
    // Try to pull top 1-2 weakest topics for a data-driven pullquote
    let weakHint = '';
    try {
      if (typeof computeWeakSpotScores === 'function') {
        const weak = computeWeakSpotScores();
        if (weak && weak.length >= 2) {
          weakHint = ` Focus: ${escHtml(weak[0].topic)} and ${escHtml(weak[1].topic)}.`;
        } else if (weak && weak.length === 1) {
          weakHint = ` Focus: ${escHtml(weak[0].topic)}.`;
        }
      }
    } catch (_) {}
    planText = `Seven questions per topic, mixed difficulty. Your <em>fastest</em> route to exam-ready.${weakHint}`;
    planMeta = 'TODAY\u2019S STUDY PLAN \u00B7 ~21 MIN \u00B7 5 TOPICS';
  }
  el.innerHTML = `
    <div class="fb-quote" aria-hidden="true">\u201C</div>
    <div class="fb-body">
      <div class="fb-text">${planText}</div>
      <div class="fb-meta">${planMeta}</div>
    </div>
    <button type="button" class="fb-cta" onclick="${ctaAction}" aria-label="${ctaLabel}">${ctaLabel} <span aria-hidden="true">\u2192</span></button>`;
  el.classList.remove('is-hidden');
}

